import{_ as a,o as r,c as s,ae as t}from"./chunks/framework.WV23YX7-.js";const o="/all-time-wrestling-rpg/screenshots/player-effective-stats.png",n="/all-time-wrestling-rpg/screenshots/player-season-summary.png",i="/all-time-wrestling-rpg/screenshots/player-career-legacy.png",c="/all-time-wrestling-rpg/screenshots/player-achievements.png",l="/all-time-wrestling-rpg/screenshots/player-season-history.png",b=JSON.parse('{"title":"Player Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/player-dashboard.md","filePath":"guide/player-dashboard.md"}'),d={name:"guide/player-dashboard.md"};function p(h,e,m,u,g,f){return r(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="player-dashboard" tabindex="-1">Player Dashboard <a class="header-anchor" href="#player-dashboard" aria-label="Permalink to &quot;Player Dashboard&quot;">​</a></h1><p>Welcome to the Player Dashboard guide. This documentation is automatically generated from the latest game features.</p><h2 id="effective-stats-and-status-cards" tabindex="-1">Effective Stats and Status Cards <a class="header-anchor" href="#effective-stats-and-status-cards" aria-label="Permalink to &quot;Effective Stats and Status Cards&quot;">​</a></h2><p>The Effective Stats section shows real-time HP, Stamina, Momentum, and Hand Size after applying all active modifiers — campaign bonuses/penalties, injuries, bumps, and Status Cards. Hover over any stat for a full breakdown. Active Status Cards appear as colour-coded badges: green for positive, red for negative.</p><p><img src="'+o+'" alt="Effective Stats and Status Cards"></p><hr><h2 id="season-summary" tabindex="-1">Season Summary <a class="header-anchor" href="#season-summary" aria-label="Permalink to &quot;Season Summary&quot;">​</a></h2><p>The Season Summary component provides a snapshot of your wrestler&#39;s performance during the currently active season, including their win-loss record, fan growth progress, and any championships or accolades earned.</p><p><img src="'+n+'" alt="Season Summary"></p><hr><h2 id="career-legacy" tabindex="-1">Career Legacy <a class="header-anchor" href="#career-legacy" aria-label="Permalink to &quot;Career Legacy&quot;">​</a></h2><p>Your persistent career progress is tracked at the account level. View your current Legacy Score, Prestige XP, and earned achievement badges directly from your dashboard. These stats persist across seasons and different wrestlers.</p><p><img src="'+i+'" alt="Career Legacy"></p><hr><h2 id="medals-achievements" tabindex="-1">Medals &amp; Achievements <a class="header-anchor" href="#medals-achievements" aria-label="Permalink to &quot;Medals &amp; Achievements&quot;">​</a></h2><p>Track your progress toward various career milestones in the Achievements tab. Each achievement awards permanent Prestige XP and a unique medal displayed on your profile.</p><p><img src="'+c+'" alt="Medals &amp; Achievements"></p><hr><h2 id="historical-season-performance" tabindex="-1">Historical Season Performance <a class="header-anchor" href="#historical-season-performance" aria-label="Permalink to &quot;Historical Season Performance&quot;">​</a></h2><p>Review your past glory by switching between seasons. The dashboard stores historical data, allowing you to track your wrestler&#39;s career trajectory and milestones over time.</p><p><img src="'+l+'" alt="Historical Season Performance"></p><hr>',22)])])}const _=a(d,[["render",p]]);export{b as __pageData,_ as default};
